      },
      {
        "from": "CartService",
        "to": "PaymentService",
        "status": "broken",
        "issue": "TIMEOUT MISMATCH: CartService timeout on PaymentService is 5s, but PaymentService's downstream call to the payment gateway has an 8s timeout. CartService will timeout and abandon the call while PaymentService is still waiting on the gateway. This creates orphaned payment requests — payments may succeed after CartService has already returned an error to the user, leading to charges with no corresponding order completion."
      },
      {
        "from": "OrderService",
        "to": "InventoryService",
        "status": "risk",
        "issue": "Retry on timeout is good, but with a 3s timeout + 1 retry, worst case is 6s for OrderService to respond. CartService gives OrderService 5s, so the retry may itself be cut short by the upstream timeout. Effective retry window is only ~2s."
      },
      {
        "from": "PaymentService",
        "to": "PaymentGateway (external)",
        "status": "risk",
        "issue": "No circuit breaker on external payment gateway. If the gateway degrades, every checkout attempt will block for up to 8s (actually orphaned after 5s from CartService side), exhausting PaymentService connection pool and threads."
      },
      {
        "from": "CartService",
        "to": "OrderService → PaymentService (sequential)",
        "status": "broken",
        "issue": "CRITICAL: No compensation or saga pattern. If OrderService succeeds (order created, inventory reserved) but PaymentService fails, there is no rollback of the order or release of reserved inventory. This creates ghost orders and stuck inventory."
      }
    ],
    "contract_compliance": "No mention of idempotency keys on any call. Payment retries (even manual ones from users) risk duplicate charges. OrderService retries to InventoryService could double-reserve stock if the first request succeeded but the response was lost.",
    "data_flow_integrity": "Broken. The synchronous chain CartService → OrderService → PaymentService has no transactional guarantee. Partial success (order created, payment failed) leaves the system in an inconsistent state with no automated recovery path. Inventory will be reserved for orders that will never be paid."
  },

  "observability_review": {
    "logging": {
      "coverage": "gaps",
      "gaps": [
        "No mention of correlation/request IDs flowing across the three services — impossible to trace a single checkout through CartService → OrderService → PaymentService",
        "No mention of logging the orphaned payment scenario (CartService timeout while PaymentService is still processing)",
        "No structured logging of compensation failures or inconsistent states"
      ]
    },
    "metrics": {
      "coverage": "gaps",
      "gaps": [
        "No latency histogram mentioned for the end-to-end checkout flow",
        "No metric tracking orphaned or abandoned payment gateway calls",
        "No metric for inventory reservation leak rate (reserved but never completed/cancelled)",
        "No circuit breaker state change metrics on CartService",
        "No payment gateway error rate metric in PaymentService"
      ]
    },
    "tracing": {
      "coverage": "gaps",
      "gaps": [
        "No distributed tracing mentioned across the three-service call chain",
        "Without tracing, diagnosing the 5s-vs-8s timeout mismatch in production will be extremely difficult — the on-call engineer will see CartService timeout errors but won't easily correlate them with successful payment gateway charges"
      ]
    },
    "debugging_capability": "Poor. At 3am, an on-call engineer will see timeout errors from CartService and have no way to determine whether the payment actually went through on the gateway side. They will need to manually cross-reference PaymentService logs with gateway records to find orphaned charges. No correlation ID makes this a needle-in-haystack exercise."
  },

  "resilience_assessment": {
    "failure_modes": [
      {
        "scenario": "Payment gateway slow (5-8s response time)",
        "handling": "unhandled",
        "recommendation": "MUST FIX: Reduce payment gateway timeout to 4s (under CartService's 5s budget) OR increase CartService timeout on PaymentService to >8s. Current config guarantees orphaned payments under load."
      },
      {
        "scenario": "OrderService succeeds, PaymentService fails",
        "handling": "unhandled",
        "recommendation": "MUST FIX: Implement a compensation mechanism — either a saga that calls OrderService to cancel/release inventory on payment failure, or switch to a reservation pattern where the order is not finalized until payment confirms."
      },
      {
        "scenario": "OrderService is down or slow",
        "handling": "partial",
        "recommendation": "Add circuit breaker on OrderService in CartService. Currently only PaymentService has a circuit breaker. A degraded OrderService will eat all CartService resources."
      },
      {
        "scenario": "InventoryService timeout with retry exceeds CartService's 5s budget",
        "handling": "unhandled",
        "recommendation": "OrderService worst-case latency (3s + 3s retry = 6s) exceeds CartService's 5s timeout. Either reduce InventoryService timeout to 2s (allowing retry within budget) or increase CartService timeout on OrderService."
